INSERT INTO public.industry_issue (full_name, first_name, last_name, headline, linkedin_url, public_identifier, raw_data) VALUES
('Frank Grassmann', 'Frank', 'Grassmann', 'Experienced Hospitality Professional', 'https://www.linkedin.com/in/frank-grassmann-80706b22', 'frank-grassmann-80706b22', $${"about": "35 years of Hospitality experience in 5 star hotels and resorts in Germany, UK, Saudi Arabia, Thailand, Mexico and Philippines.\nStrong operations experience in the 5* deluxe market, proven success with major refurbishments, relaunches and openings.\n\nCAREER OBJECTIVE\n\nHaving started my career in classic European luxury hotels I embarked on my planned path via the Middle East and the Americas to Asia. I developed into a results-orientated as well as quality operator by working with multi-national corporations and upscale independent operators.\n\nSKILLS\n\nWith my background in F&B I consider myself a hands-on manager. My supervisors have appraised me regularly as having exceptional guest contact skills and being able to maintain effective relationships with my employees. I am efficient in handling administrative tasks to maximize time spent with sales, guests, staff and work on innovation.\nPrevious work in large multi-national companies such as Intercontinental and Starwood taught me systems, procedures and structure, while work with more independent operators such as Dusit, Six Senses and Soneva gave me freedom to express my ideas and implement them based on my extensive experience. I take on challenges while setting high individual and team standards. Through extensive cross-cultural experiences I am able to manage difficult situations/scenarios across countries and operating environments.\n\nKEY FOCUS\n\nPeople development, service excellence, guest satisfaction, Sales & Marketing and profitability\n\nSpecialties: Refurbishment, Relaunch, Opening \nConcept Development\nFood & Beverage", "addressCountryOnly": "Thailand", "addressWithCountry": "Greater Phuket Area, Thailand", "addressWithoutCountry": "Greater Phuket Area", "backgroundPic": "https://media.licdn.com/dms/image/v2/D5616AQFxyZsJBmEgpw/profile-displaybackgroundimage-shrink_350_1400/profile-displaybackgroundimage-shrink_350_1400/0/1703413371760?e=1778112000&v=beta&t=nxUXGSgp8xi9fQH-C9IJN2U1rM9eRMB7KNQgBaYhwFQ", "companyName": "The Nai Harn", "connections": "2160", "currentJobDuration": "11 yrs 2 mos", "currentJobDurationInYrs": "11.17", "educations/0/period/endedOn/month": "0", "educations/0/period/endedOn/year": "1991", "educations/0/period/startedOn/month": "0", "educations/0/period/startedOn/year": "1988", "educations/0/subtitle": "Hotelfachmann, Hotelfachmann", "educations/0/title": "Albrecht-Dürer-Schule, Berufskolleg Düsseldorf", "educations/1/period/endedOn/month": "0", "educations/1/period/endedOn/year": "1986", "educations/1/period/startedOn/month": "0", "educations/1/period/startedOn/year": "1973", "educations/1/subtitle": "Abitur", "educations/1/title": "Konrad-Adenauer-Gymnasium, Langenfeld/Rheinland", "experiences/0/companyName": "The Nai Harn", "experiences/0/employmentType": "Full-time", "experiences/0/jobDescription": "Previously operated under the name of \"Royal Phuket Yacht Club\" this property is now under new ownership and closed for an exciting renovation and rebranding over an 18 month period. As the only member of Leading Hotels of the World  in Phuket it is now open since 28th December 2015.", "experiences/0/jobStartedOn": "3-2015", "experiences/0/jobStillWorking": "true", "experiences/0/title": "General Manager", "experiences/1/companyName": "www.jamessuckling.com", "experiences/1/jobDescription": "James Suckling is one of today’s leading wine critics, whose views are read and respected by wine lovers, serious wine collectors, and the international wine trade in general. He is currently the wine editor for Asia Tatler Magazines and its nine luxury magazines in the region, including Hong Kong Tatler, Shangliu Tatler, Singapore Tatler, and Thailand Tatler. However, most of his time is spent managing his own website, JamesSuckling.com, as well as promoting his 100 Points wine glassware with Lalique, the famous French crystal house. He recently launched a limited eidtion wine briefcase with Lalique and Salvatore Ferragamo, the famous Itlalian fashion house.Suckling spent nearly 30 years as Senior Editor and European Bureau Chief of American magazine The Wine Spectator, and as European Editor of Cigar Aficionado. On his departure from the magazines, Forbes called the Los Angeles-born writer “one of the world’s most powerful wine critics.”", "experiences/1/jobEndedOn": "2-2015", "experiences/1/jobStartedOn": "7-2014", "experiences/1/jobStillWorking": "false", "experiences/1/title": "Project Coordinator", "experiences/2/companyId": "3552668", "experiences/2/companyIndustry": "Hospitality", "experiences/2/companyLink1": "https://www.linkedin.com/company/soneva/", "experiences/2/companyName": "Soneva Kiri Resort, Spa and Private Residences", "experiences/2/companySize": "1001-5000", "experiences/2/companyUrn": "urn:li:fsd_company:3552668", "experiences/2/companyWebsite": "http://www.soneva.com", "experiences/2/jobDescription": "Koh Kood is Thailand as it was years ago. One hour’s flight from Bangkok by private plane it offers an unrivalled combination of luxury, environmentally friendly design and unforgettable, authentic Thai experiences. Located on the idyllic beach or sunny slopes in the rainforest, all have stunning infinity pools, impossibly chic furnishings, personal electric buggies and impeccable service by Mr./Ms. Friday private butlers. Barefoot Intelligent Luxury at its best. No news, no shoes, Thai style.", "experiences/2/jobEndedOn": "6-2014", "experiences/2/jobLocation": "Koh Kood, Thailand", "experiences/2/jobLocationCountry": "AE", "experiences/2/jobStartedOn": "7-2012", "experiences/2/jobStillWorking": "false", "experiences/2/logo": "https://media.licdn.com/dms/image/v2/C4D0BAQGCjRFBhDtk8Q/company-logo_400_400/company-logo_400_400/0/1636122596952/soneva_logo?e=1778112000&v=beta&t=Qxx7ztmbtbsrVVMLdjJ692dYuBPMJc0yXdjYAFl4YHM", "experiences/2/title": "General Manager", "experiences/3/companyId": "35446", "experiences/3/companyIndustry": "Hospitality", "experiences/3/companyLink1": "https://www.linkedin.com/company/six-senses-hotels-resorts/", "experiences/3/companyName": "Evason Phuket & Bon Island", "experiences/3/companySize": "1001-5000", "experiences/3/companyUrn": "urn:li:fsd_company:35446", "experiences/3/companyWebsite": "http://www.sixsenses.com", "experiences/3/jobDescription": "The Evason Phuket Resort and Six Senses Spa is located at Rawai Beach on the southeastern side of Phuket Island. It is set amongst 64 acres of beautifully landscaped tropical gardens, facing the Andaman Sea. \nThe Resort embodies the Evason philosophy of redefining experiences, and as such presents a refreshing reinterpretation of a five star resort designed to appeal to today's more sophisticated travellers. \nGuest rooms, Suites and Pool Villas feature a fresh and unconventional design, which is entirely new for Phuket. Most rooms have bright, open-style bathrooms so as to create more space and light in the room. A totally new approach to materials, finishes and colors contribute to a refreshing new holiday experience. \nEvason service standards ensure great attention to detail and a welcoming and friendly atmosphere. It is the delivery of the service that differentiates The Evason approach from other top Resorts.", "experiences/3/jobEndedOn": "7-2012", "experiences/3/jobLocation": "Phuket, Thailand", "experiences/3/jobLocationCountry": "TH", "experiences/3/jobStartedOn": "8-2008", "experiences/3/jobStillWorking": "false", "experiences/3/logo": "https://media.licdn.com/dms/image/v2/C560BAQGbwS6ZcX6Ktg/company-logo_400_400/company-logo_400_400/0/1633427164381/six_senses_resorts__spas_logo?e=1778112000&v=beta&t=FgmbAMpuQ5qoSi2i7ehv2VuZLdhv1yPTiwrgvoVW2pI", "experiences/3/title": "General Manager", "experiences/4/companyId": "73878", "experiences/4/companyIndustry": "Hospitality", "experiences/