ational Airport.\nSink into the new Sheraton Sweet Sleeper® Bed in all 755 spacious guest rooms. Whether you want a peaceful night’s sleep for a meeting or a relaxing vacation, you’ll love the custom-designed plush mattress, cozy comforter, and five cushy pillows. Wireless High Speed Internet Access will keep you connected to home or the office.\nGather with friends or family at our distinct restaurants and lounges. Listen to live Mariachi music in the warm atmosphere of our Jorongo Bar. Enjoy the best pastas al dente at our award-winning Ristorante Amici. Car rental services, a travel agency, and currency exchange are available onsite to make your stay more convenient. Our multilingual staff is always available with attentive service.", "experiences/5/jobEndedOn": "4-2006", "experiences/5/jobLocation": "Mexico City, D.F., Mexico", "experiences/5/jobStartedOn": "11-2004", "experiences/5/jobStillWorking": "false", "experiences/5/title": "Executive Assistant Manager", "experiences/6/companyId": "73878", "experiences/6/companyIndustry": "Hospitality", "experiences/6/companyLink1": "https://www.linkedin.com/company/dusit-hotels-and-resorts/", "experiences/6/companyName": "Dusit Thani Bangkok", "experiences/6/companySize": "5001-10000", "experiences/6/companyUrn": "urn:li:fsd_company:73878", "experiences/6/companyWebsite": "http://www.dusit.com", "experiences/6/jobEndedOn": "10-2004", "experiences/6/jobLocation": "Bangkok, Thailand", "experiences/6/jobLocationCountry": "TH", "experiences/6/jobStartedOn": "11-2001", "experiences/6/jobStillWorking": "false", "experiences/6/logo": "https://media.licdn.com/dms/image/v2/D560BAQGWMHIk9QEgDw/company-logo_400_400/B56ZoZPoypJQAY-/0/1761360122041/dusit_hotels_and_resorts_logo?e=1778112000&v=beta&t=FLJ8WBd5R9JloKB_DRhwqZyBPeZ9Snnh_2Lf31yw6XQ", "experiences/6/title": "Director of Food & Beverage", "experiences/7/companyId": "73878", "experiences/7/companyIndustry": "Hospitality", "experiences/7/companyLink1": "https://www.linkedin.c